        expect(data.bailout, closeTo(6.0, 0.001));
        expect(data.colorScheme, 3);
        expect(data.power, closeTo(8.0, 0.001));
        expect(data.juliaX, closeTo(-0.7, 0.001));
        expect(data.juliaY, closeTo(0.27, 0.001));
