static String _formatDouble(double value) {
  // Keep integer-looking values compact without truncating significant deep-zoom
  // coordinates that need more than six decimal places to round-trip.
  if (value == value.truncateToDouble()) {
    return value.toInt().toString();
  }

  final compactFixed = value
      .toStringAsFixed(6)
      .replaceAll(RegExp(r'\.?0+$'), '');
  if (double.tryParse(compactFixed) == value) {
    return compactFixed;
  }

  return value.toString();
}

